mapper.select:
SELECT am.id, am.name, am.description, am.question_bank_id AS questionBankId, am.textbook_id AS textbookId, am.status, am.creator, am.add_datetime AS addDatetime, am.operator, am.operation_datetime AS operationDatetime, (SELECT name FROM teaching_question_bank WHERE id = am.question_bank_id LIMIT 1) AS questionBankName, (SELECT textbook_name FROM textbook WHERE id = am.textbook_id LIMIT 1) AS textbookName, (SELECT nickname FROM sys_tbuser WHERE id = am.creator LIMIT 1) AS creatorName, (SELECT nickname FROM sys_tbuser WHERE id = am.operator LIMIT 1) AS operatorName, (SELECT COUNT(*) FROM application_materials_mapping WHERE application_material_id = am.id) AS teachingMaterialsCount FROM application_materials am
AND am.name LIKE '%' || #{param.name} || '%'
AND am.question_bank_id = #{param.questionBankId}
AND am.status = #{param.status}
ORDER BY am.add_datetime
ASC DESC
